import{_ as e,o as l,c as a,al as n}from"./chunks/framework.GnR-YWkE.js";const f=JSON.parse('{"title":"CLI 工具概览","description":"","frontmatter":{},"headers":[],"relativePath":"cli/index.md","filePath":"zh-CN/cli/index.md","lastUpdated":1771838368000}'),d={name:"cli/index.md"};function i(r,t,s,o,c,h){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="cli-工具概览" tabindex="-1">CLI 工具概览 <a class="header-anchor" href="#cli-工具概览" aria-label="Permalink to “CLI 工具概览”">​</a></h1><p>QuecPanel CLI (<code>@quec/oem-cli</code>) 是专为 QuecPanel 开发者打造的一站式命令行工具。它不仅简化了项目的初始化流程，还提供了从物模型生成到多语言管理的全链路支持。</p><h2 id="为什么使用-cli" tabindex="-1">为什么使用 CLI？ <a class="header-anchor" href="#为什么使用-cli" aria-label="Permalink to “为什么使用 CLI？”">​</a></h2><ul><li><strong>快速启动</strong>：通过标准化模板一键创建工程，无需手动搭建环境。</li><li><strong>自动化构建</strong>：集成了 Webpack 等构建工具，简化打包发布流程。</li><li><strong>代码生成</strong>：自动从物模型 JSON 生成 TypeScript 类型定义，减少重复劳动。</li><li><strong>多语言支持</strong>：一键扫描并导出多语言配置，提升国际化开发效率。</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to “核心功能”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">功能模块</th><th style="text-align:left;">对应命令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工程管理</strong></td><td style="text-align:left;"><a href="./commands.html#createpanel"><code>createPanel</code></a></td><td style="text-align:left;">创建新的面板项目</td></tr><tr><td style="text-align:left;"><strong>构建发布</strong></td><td style="text-align:left;"><a href="./commands.html#buildpanel"><code>buildPanel</code></a></td><td style="text-align:left;">生成 Android/iOS 离线发布包</td></tr><tr><td style="text-align:left;"><strong>物模型</strong></td><td style="text-align:left;"><a href="./commands.html#gentslmodel"><code>genTslModel</code></a></td><td style="text-align:left;">生成 TSL 类型定义与配置</td></tr><tr><td style="text-align:left;"><strong>多语言</strong></td><td style="text-align:left;"><a href="./commands.html#geni18n"><code>genI18n</code></a></td><td style="text-align:left;">导出多语言 Excel 文件</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><ul><li><a href="/cli/install.html">安装 CLI</a> - 了解如何安装和配置开发环境。</li><li><a href="/cli/commands.html">命令行参考</a> - 查看所有命令的详细参数和用法。</li></ul>',8)])])}const m=e(d,[["render",i]]);export{f as __pageData,m as default};
